      if (k in custVal) val=custVal[k]; else val=defVal[k]
      print key "=" val > out
    }
    for (j=1; j<=nExtra[sec]; j++) {
      key=extraKeyOrder[sec,j]
      k=sec SUBSEP key
      print key "=" custVal[k] > out
    }
    if (i<nSec || nCustomSec>0) print "" > out
  }

  for (i=1; i<=nCustomSec; i++) {
    sec=customSecOrder[i]
    print "[" sec "]" > out
    for (j=1; j<=nNewKeys[sec]; j++) {
      key=newSecKeyOrder[sec,j]
      k=sec SUBSEP key
      print key "=" custVal[k] > out
    }
    if (i<nCustomSec) print "" > out
  }
}
